import{BaseMixin}from"../base/base-mixin.js";import{constants}from"../core/constants.js";import{events}from"../core/events.js";const INPUT_CSS_CLASS="dc-text-filter-input";class TextFilterWidget extends BaseMixin{constructor(t,e){super(t,e),this.configure({placeHolder:"search",normalize:t=>t.toLowerCase(),filterFunctionFactory:e=>(e=this._conf.normalize(e),t=>-1!==this._conf.normalize(t).indexOf(e))})}configure(t){return super.configure(t),this}conf(){return this._conf}_doRender(){this.select("input").remove(),this._input=this.root().append("input").classed(INPUT_CSS_CLASS,!0);const t=this;return this._input.on("input",function(){t.dataProvider().conf().dimension.filterFunction(t._conf.filterFunctionFactory(this.value)),events.trigger(()=>{t.redrawGroup()},constants.EVENT_DELAY)}),this._doRedraw(),this}_doRedraw(){return this.root().selectAll("input").attr("placeholder",this._conf.placeHolder),this}}export{TextFilterWidget};